import type { HTMLAttributes, ReactNode } from 'react';
import type { TestComponentProps } from 'src/types/test-component';
export interface RatingProps extends Omit<HTMLAttributes<HTMLElement>, 'onChange'>, TestComponentProps {
    /**
     * Выбранное значение (индекс)
     */
    value?: number;
    /**
     * Тип рейтинга. Звезды, цифры или кастом
     * @default star
     */
    item?: 'star' | 'number' | ((index: number) => ReactNode);
    /**
     * Максимальный индекс
     * @default 5
     */
    maxIndex?: number;
    /**
     * Минимальный индекс
     * @default 1
     */
    minIndex?: number;
    /**
     * Вызывается при выборе значения
     */
    onChange?: (index: number) => void;
    /**
     * Функция вызывается при ховере на одной из иконок
     */
    onHover?: (index: number | null) => void;
    /**
     * Подписи снизу, задается сразу слева и справа
     */
    caption?: {
        left: string;
        right: string;
    };
    /**
     * Текст над иконками, показывает выбранное значение
     * Может быть строкой или кастомным элементом
     */
    score?: ReactNode | string;
    /**
     * Дополнительный CSS класс
     */
    className?: string;
    /**
     * Включает disabled состояние компонента
     */
    disabled?: boolean;
    /**
     * Отключает все события на ховер/клик, делает компонент только для чтения
     */
    readonly?: boolean;
}
